 namespace WPAICG\Chat\Initializer; use WPAICG\Core\Stream\Handler\SSEHandler; if (!defined('ABSPATH')) { exit; } function register_hooks_sse_ajax_logic(?SSEHandler $sse_handler): void { if ($sse_handler) { add_action('wp_ajax_aipkit_cache_sse_message', [$sse_handler, 'ajax_cache_sse_message']); add_action('wp_ajax_nopriv_aipkit_cache_sse_message', [$sse_handler, 'ajax_cache_sse_message']); add_action('wp_ajax_aipkit_frontend_chat_stream', [$sse_handler, 'ajax_frontend_chat_stream']); add_action('wp_ajax_nopriv_aipkit_frontend_chat_stream', [$sse_handler, 'ajax_frontend_chat_stream']); } }